class Solution {
    public int maximumLength(String s) {
        int maxLen = -1;
        for (int len = s.length(); len >= 1; len--) {
            for (int i = 0; i <= s.length() - len; i++) {
                String substr = s.substring(i, i + len);
                if (isSpecial(substr) && countOccurrences(s, substr) >= 3) {
                    maxLen = Math.max(maxLen, len);
                }
            }
        }
        return maxLen;
    }

    private boolean isSpecial(String s) {
        char c = s.charAt(0);
        for (int i = 1; i < s.length(); i++) {
            if (s.charAt(i) != c) {
                return false;
            }
        }
        return true;
    }

    private int countOccurrences(String s, String substr) {
        int count = 0;
        int idx = 0;
        while ((idx = s.indexOf(substr, idx)) != -1) {
            count++;
            idx += 1;
        }
        return count;
    }
}
